queries.sparql:
PREFIX : <http://ambrosia.example.org/demographics#>
PREFIX p: <http://ambrosia.example.org/demographics/prop#>
SELECT ?val WHERE { ?x a :OwnerPercentage ; p:Percentage ?pct ; p:TotalPopulation ?tp . BIND(?pct * ?tp / 100 AS ?val) }

PREFIX : <http://ambrosia.example.org/demographics#>
PREFIX p: <http://ambrosia.example.org/demographics/prop#>
SELECT ?val ?noh WHERE {
  ?x a :OwnerPercentage ; p:Year ?y ; p:Percentage ?pct ; p:TotalPopulation ?tp .
  BIND(?pct * ?tp / 100 AS ?val)
  OPTIONAL { ?n a :NumbersOfOwners ; p:Year ?y2 ; p:NumberOfHouseholds ?noh . FILTER(STR(?y)=STR(?y2)) }
}

PREFIX : <http://ambrosia.example.org/demographics#>
PREFIX p: <http://ambrosia.example.org/demographics/prop#>
SELECT ?val WHERE { ?x a :OwnerPercentage ; p:Year ?y ; p:Percentage ?pct ; p:TotalPopulation ?tp . FILTER(?y=2023) BIND(?pct * ?tp / 100 AS ?val) }

PREFIX : <http://ambrosia.example.org/demographics#>
PREFIX p: <http://ambrosia.example.org/demographics/prop#>
SELECT ?val ?noh WHERE {
  ?x a :OwnerPercentage ; p:Year ?y ; p:Percentage ?pct ; p:TotalPopulation ?tp . FILTER(?y=2023)
  BIND(?pct * ?tp / 100 AS ?val)
  OPTIONAL { ?n a :NumbersOfOwners ; p:Year ?y2 ; p:NumberOfHouseholds ?noh . FILTER(STR(?y)=STR(?y2)) }
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/demographics#>
PREFIX p: <http://ambrosia.example.org/demographics/prop#>
CHOICE vague {
  component: { SELECT ?val WHERE { ?x a :OwnerPercentage ; p:Percentage ?pct ; p:TotalPopulation ?tp . BIND(?pct * ?tp / 100 AS ?val) } }
  full: { SELECT ?val ?noh WHERE {
  ?x a :OwnerPercentage ; p:Year ?y ; p:Percentage ?pct ; p:TotalPopulation ?tp .
  BIND(?pct * ?tp / 100 AS ?val)
  OPTIONAL { ?n a :NumbersOfOwners ; p:Year ?y2 ; p:NumberOfHouseholds ?noh . FILTER(STR(?y)=STR(?y2)) }
} }
  component_2: { SELECT ?numberofhouseholds WHERE {
  ?numbersofowners a :NumbersOfOwners .
  ?numbersofowners p:NumberOfHouseholds ?numberofhouseholds .
} }
}

PREFIX : <http://ambrosia.example.org/demographics#>
PREFIX p: <http://ambrosia.example.org/demographics/prop#>
CHOICE vague {
  component: { SELECT ?val WHERE { ?x a :OwnerPercentage ; p:Year ?y ; p:Percentage ?pct ; p:TotalPopulation ?tp . FILTER(?y=2023) BIND(?pct * ?tp / 100 AS ?val) } }
  component_2: { SELECT ?numberofhouseholds WHERE {
  ?o a :NumbersOfOwners .
  ?o p:NumberOfHouseholds ?numberofhouseholds .
  ?o p:Year ?year_f .
  FILTER(?year_f = 2023)
} }
  full: { SELECT ?val ?noh WHERE {
  ?x a :OwnerPercentage ; p:Year ?y ; p:Percentage ?pct ; p:TotalPopulation ?tp . FILTER(?y=2023)
  BIND(?pct * ?tp / 100 AS ?val)
  OPTIONAL { ?n a :NumbersOfOwners ; p:Year ?y2 ; p:NumberOfHouseholds ?noh . FILTER(STR(?y)=STR(?y2)) }
} }
}
